const feeds = $input.all().map(i => i.json);
const feed = feeds.find(f => /sun[\s-]?times/i.test(f.title || ''));
if (!feed) throw new Error('Sun-Times feed not found in Miniflux');
return [{ json: { feedId: feed.id } }];

const all = $input.first().json.entries || [];
const entries = all.filter(e => !/obituar|dies at|dead at|in memoriam/i.test(`${e.title} ${e.url}`));
if (!entries.length) throw new Error('no Sun-Times entries in the last 7 days');
const text = entries.map(e =>
  `## ${e.title} (${e.published_at.slice(0, 10)})\n` +
  (e.content || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim().slice(0, 1500)
).join('\n\n');
const sat = $now.plus({ days: 1 }).toFormat('MMM d');
const sun = $now.plus({ days: 2 }).toFormat('MMM d');
const payload = {
  model: 'qwen3',
  temperature: 0.3,
  response_format: { type: 'json_schema', json_schema: { name: 'digest', schema: { type: 'object', properties: { week: { type: 'array', items: { type: 'string' } }, weekend: { type: 'array', items: { type: 'string' } } }, required: ['week', 'weekend'] } } },
  messages: [
    { role: 'system', content: 'You summarize local news into JSON. /no_think' },
    { role: 'user', content: `From this week's Chicago Sun-Times articles, build a "Chicago Happenings" digest as JSON. "week": one-line summaries of the top local stories of the week, especially city/state politics. "weekend": events, openings, games, and closures happening Sat ${sat} or Sun ${sun}. Skip national wire stories and omit obituaries or death notices entirely.\n\n${text}` }
  ]
};
return [{ json: { payload, count: entries.length } }];

const d = JSON.parse($input.first().json.choices[0].message.content);
const s = $getWorkflowStaticData('global');
s.digest = { week: d.week, weekend: d.weekend, updated: $now.toISO() };
return [{ json: s.digest }];
